        SimpleAltarRecipeBuilder.builder().createRecipe((ForgeRegistryEntry<?>)ItemsAS.RESONATOR, AltarType.DISCOVERY).setStarlightRequirement(0.15f).setInputs(AltarRecipeGrid.builder().patternLine(" A ").patternLine("MLM").patternLine("IGI").key('A', (ItemLike)ItemsAS.AQUAMARINE).key('M', (ItemLike)BlocksAS.MARBLE_RAW).key('L', (Fluid)FluidsAS.LIQUID_STARLIGHT_SOURCE).key('G', (ITag.INamedTag<Item>)Tags.Items.INGOTS_GOLD).key('I', (ItemLike)BlocksAS.INFUSED_WOOD)).addOutput(ItemResonator.setCurrentUpgradeUnsafe(ItemResonator.setUpgradeUnlocked(new ItemStack((ItemLike)ItemsAS.RESONATOR), ItemResonator.ResonatorUpgrade.STARLIGHT), ItemResonator.ResonatorUpgrade.STARLIGHT)).build(registrar);
